import React, { useState, useEffect, useRef } from 'react';

const LOGO = process.env.PUBLIC_URL + '/logo.png';

// ── Helpers ───────────────────────────────────────────────────────
function useCountUp(target, duration = 2000, start = false) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!start) return;
    let startTime = null;
    const step = (ts) => {
      if (!startTime) startTime = ts;
      const progress = Math.min((ts - startTime) / duration, 1);
      setVal(Math.floor(progress * target));
      if (progress < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [start, target, duration]);
  return val;
}

function useInView(ref) {
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setInView(true); }, { threshold: 0.3 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [ref]);
  return inView;
}

// ── Stat Counter ──────────────────────────────────────────────────
function StatCounter({ value, suffix = '', label, inView }) {
  const num = useCountUp(value, 1800, inView);
  return (
    <div style={{ textAlign: 'center', padding: '0 24px' }}>
      <div style={{ fontSize: 48, fontWeight: 900, color: '#fff', fontFamily: 'Manrope,sans-serif', lineHeight: 1 }}>
        {num}{suffix}
      </div>
      <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.6)', marginTop: 8, fontWeight: 600, letterSpacing: '0.05em' }}>{label}</div>
    </div>
  );
}

export default function LandingPage() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [popup, setPopup] = useState(false);
  const statsRef = useRef(null);
  const statsInView = useInView(statsRef);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  // Show popup after 5 seconds
  useEffect(() => {
    const t = setTimeout(() => setPopup(true), 5000);
    return () => clearTimeout(t);
  }, []);

  const scrollTo = (id) => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
    setMenuOpen(false);
  };

  const NAV_LINKS = [
    { label: 'About', id: 'about' },
    { label: 'Academics', id: 'academics' },
    { label: 'Facilities', id: 'facilities' },
    { label: 'Gallery', id: 'gallery' },
    { label: 'Contact', id: 'contact' },
  ];

  const VALUES = [
    { icon: '📚', title: 'Quality Education', desc: 'Rigorous academics with a focus on conceptual clarity and critical thinking.' },
    { icon: '🏃', title: 'Physical Education', desc: 'Sports and fitness programs to build healthy, disciplined minds and bodies.' },
    { icon: '🌱', title: 'Moral Values', desc: 'Character building through ethics, integrity, and community service.' },
    { icon: '🤝', title: 'Social Development', desc: 'Collaborative learning that prepares students for a diverse world.' },
  ];

  const FACILITIES = [
    { icon: '🔬', title: 'Science Labs', desc: 'Fully equipped Physics, Chemistry & Biology laboratories.' },
    { icon: '💻', title: 'Computer Lab', desc: 'Modern computer lab with high-speed internet access.' },
    { icon: '📖', title: 'Library', desc: 'Extensive collection of books, journals and digital resources.' },
    { icon: '⚽', title: 'Sports Ground', desc: 'Large playground with facilities for cricket, football and athletics.' },
    { icon: '🎨', title: 'Art & Craft', desc: 'Dedicated studio for painting, sculpture and creative arts.' },
    { icon: '🎵', title: 'Music Room', desc: 'Instruments and trained faculty for classical and modern music.' },
  ];

  const NOTICES = [
    { date: 'Mar 20, 2026', title: 'Annual Sports Day — Registration Open', tag: 'Event' },
    { date: 'Mar 15, 2026', title: 'Class X & XII Board Exam Schedule Released', tag: 'Exam' },
    { date: 'Mar 10, 2026', title: 'Parent-Teacher Meeting — April 5, 2026', tag: 'Notice' },
    { date: 'Mar 05, 2026', title: 'Admission Open for Session 2026-2027', tag: 'Admission' },
    { date: 'Feb 28, 2026', title: 'Science Exhibition Results Announced', tag: 'Result' },
  ];

  const tagColor = { Event: '#3b82f6', Exam: '#8b5cf6', Notice: '#f59e0b', Admission: '#10b981', Result: '#ef4444' };

  return (
    <div style={{ fontFamily: 'Inter, sans-serif', color: '#1e293b', background: '#fff', overflowX: 'hidden' }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Manrope:wght@400;600;700;800;900&family=Inter:wght@400;500;600;700&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        html { scroll-behavior: smooth; }
        .lp-nav-link { cursor: pointer; font-weight: 600; font-size: 14px; transition: color 200ms; }
        .lp-nav-link:hover { color: #1960a3 !important; }
        .lp-card { transition: transform 200ms, box-shadow 200ms; }
        .lp-card:hover { transform: translateY(-4px); box-shadow: 0 16px 40px rgba(0,32,69,0.12) !important; }
        .lp-btn-primary { background: linear-gradient(135deg,#002045,#1960a3); color: #fff; border: none; border-radius: 12px; padding: 14px 32px; font-size: 15px; font-weight: 700; cursor: pointer; transition: all 200ms; font-family: inherit; }
        .lp-btn-primary:hover { transform: translateY(-2px); box-shadow: 0 8px 24px rgba(25,96,163,0.4); }
        .lp-btn-outline { background: transparent; color: #fff; border: 2px solid rgba(255,255,255,0.6); border-radius: 12px; padding: 13px 28px; font-size: 15px; font-weight: 700; cursor: pointer; transition: all 200ms; font-family: inherit; }
        .lp-btn-outline:hover { background: rgba(255,255,255,0.12); border-color: #fff; }
        @keyframes lp-fade-up { from { opacity:0; transform:translateY(30px); } to { opacity:1; transform:none; } }
        @keyframes lp-float { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-12px)} }
        @keyframes lp-pulse { 0%,100%{opacity:0.4} 50%{opacity:0.9} }
        .lp-hero-text { animation: lp-fade-up 800ms 200ms both; }
        .lp-hero-sub { animation: lp-fade-up 800ms 400ms both; }
        .lp-hero-btns { animation: lp-fade-up 800ms 600ms both; }
        .lp-section { padding: 80px 0; }
        .lp-container { max-width: 1200px; margin: 0 auto; padding: 0 24px; }
        .lp-grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: center; }
        .lp-grid-3 { display: grid; grid-template-columns: repeat(3,1fr); gap: 24px; }
        .lp-grid-4 { display: grid; grid-template-columns: repeat(4,1fr); gap: 24px; }
        @media(max-width:900px){.lp-grid-2{grid-template-columns:1fr;}.lp-grid-3{grid-template-columns:1fr 1fr;}.lp-grid-4{grid-template-columns:1fr 1fr;}}
        @media(max-width:600px){.lp-grid-3,.lp-grid-4{grid-template-columns:1fr;}.lp-hero-title{font-size:36px!important;}}
        .lp-section-label { font-size: 11px; font-weight: 800; color: #1960a3; letter-spacing: 0.2em; text-transform: uppercase; margin-bottom: 12px; }
        .lp-section-title { font-size: 38px; font-weight: 900; color: #1e293b; font-family: Manrope,sans-serif; line-height: 1.15; margin-bottom: 16px; }
        .lp-section-desc { font-size: 15px; color: #64748b; line-height: 1.75; }
        .notice-row:hover { background: #f8fafc !important; }
      `}</style>

      {/* ── Navbar ── */}
      <nav style={{
        position: 'fixed', top: 0, left: 0, right: 0, zIndex: 1000,
        background: scrolled ? 'rgba(255,255,255,0.97)' : 'transparent',
        backdropFilter: scrolled ? 'blur(12px)' : 'none',
        boxShadow: scrolled ? '0 2px 20px rgba(0,0,0,0.08)' : 'none',
        transition: 'all 300ms',
        padding: '0 24px',
      }}>
        <div style={{ maxWidth: 1200, margin: '0 auto', display: 'flex', alignItems: 'center', height: 70 }}>
          {/* Logo */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 12, flex: 1 }}>
            <div style={{ width: 42, height: 42, borderRadius: 12, background: scrolled ? '#eff6ff' : 'rgba(255,255,255,0.15)', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden' }}>
              <img src={LOGO} alt="LKPS" style={{ width: 32, height: 32, objectFit: 'contain' }} onError={e => { e.target.style.display = 'none'; e.target.parentNode.innerHTML = '🏫'; }} />
            </div>
            <div>
              <div style={{ fontSize: 14, fontWeight: 900, color: scrolled ? '#1e293b' : '#fff', fontFamily: 'Manrope,sans-serif', lineHeight: 1.1 }}>LORD KRISHNA PUBLIC SCHOOL</div>
              <div style={{ fontSize: 10, color: scrolled ? '#64748b' : 'rgba(255,255,255,0.6)', fontWeight: 600, letterSpacing: '0.08em' }}>ISHAPUR, MATHURA · EST. 2009</div>
            </div>
          </div>

          {/* Desktop nav */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 32 }} className="hidden lg:flex">
            {NAV_LINKS.map(l => (
              <span key={l.id} className="lp-nav-link" onClick={() => scrollTo(l.id)}
                style={{ color: scrolled ? '#475569' : 'rgba(255,255,255,0.85)' }}>{l.label}</span>
            ))}
            <button className="lp-btn-primary" onClick={() => window.location.href = '/login'}
              style={{ padding: '9px 22px', fontSize: 13, borderRadius: 10 }}>
              Portal Login
            </button>
          </div>

          {/* Mobile hamburger */}
          <button onClick={() => setMenuOpen(v => !v)}
            style={{ background: 'none', border: 'none', cursor: 'pointer', padding: 8, color: scrolled ? '#1e293b' : '#fff', display: 'none' }}
            className="lg:hidden">
            <span style={{ fontSize: 24 }}>{menuOpen ? '✕' : '☰'}</span>
          </button>
        </div>

        {/* Mobile menu */}
        {menuOpen && (
          <div style={{ background: '#fff', borderTop: '1px solid #f1f5f9', padding: '16px 24px' }}>
            {NAV_LINKS.map(l => (
              <div key={l.id} className="lp-nav-link" onClick={() => scrollTo(l.id)}
                style={{ color: '#475569', padding: '12px 0', borderBottom: '1px solid #f8fafc' }}>{l.label}</div>
            ))}
            <button className="lp-btn-primary" onClick={() => window.location.href = '/login'}
              style={{ marginTop: 16, width: '100%' }}>Portal Login</button>
          </div>
        )}
      </nav>

      {/* ── Hero ── */}
      <section style={{
        minHeight: '100vh', background: 'linear-gradient(145deg,#001530 0%,#002045 55%,#0a3060 100%)',
        display: 'flex', alignItems: 'center', position: 'relative', overflow: 'hidden',
      }}>
        {/* Grid bg */}
        <div style={{ position: 'absolute', inset: 0, backgroundImage: 'linear-gradient(rgba(255,255,255,0.025) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,0.025) 1px,transparent 1px)', backgroundSize: '52px 52px', pointerEvents: 'none' }} />
        {/* Orbs */}
        {[{ w: 500, h: 500, top: '-150px', right: '-150px', dur: '20s' }, { w: 300, h: 300, bottom: '-80px', left: '-80px', dur: '16s' }, { w: 150, h: 150, top: '40%', left: '15%', dur: '12s' }].map((o, i) => (
          <div key={i} style={{ position: 'absolute', width: o.w, height: o.h, top: o.top, right: o.right, bottom: o.bottom, left: o.left, borderRadius: '50%', background: 'rgba(255,255,255,0.04)', filter: 'blur(2px)', animation: `lp-float ${o.dur} ease-in-out infinite`, pointerEvents: 'none' }} />
        ))}

        <div className="lp-container" style={{ position: 'relative', zIndex: 1, paddingTop: 100, paddingBottom: 80 }}>
          <div style={{ maxWidth: 720 }}>
            <div className="lp-hero-text" style={{ display: 'inline-flex', alignItems: 'center', gap: 8, padding: '6px 16px', borderRadius: 20, background: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.15)', marginBottom: 28 }}>
              <span style={{ fontSize: 12 }}>🏫</span>
              <span style={{ fontSize: 11, fontWeight: 700, color: 'rgba(255,255,255,0.7)', letterSpacing: '0.12em', textTransform: 'uppercase' }}>Est. 2009 · Ishapur, Laxminagar, Mathura</span>
            </div>
            <h1 className="lp-hero-text lp-hero-title" style={{ fontSize: 62, fontWeight: 900, color: '#fff', fontFamily: 'Manrope,sans-serif', lineHeight: 1.06, letterSpacing: '-0.03em', marginBottom: 24 }}>
              Lord Krishna<br />
              <span style={{ background: 'linear-gradient(90deg,#60a5fa,#a78bfa)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text' }}>Public School</span>
            </h1>
            <p className="lp-hero-sub" style={{ fontSize: 18, color: 'rgba(255,255,255,0.6)', lineHeight: 1.75, maxWidth: 560, marginBottom: 40 }}>
              Nurturing young minds with values, discipline, and academic excellence. Building tomorrow's leaders in the heart of Mathura.
            </p>
            <div className="lp-hero-btns" style={{ display: 'flex', gap: 16, flexWrap: 'wrap' }}>
              <button className="lp-btn-primary" onClick={() => scrollTo('about')}>Explore School</button>
              <button className="lp-btn-outline" onClick={() => window.location.href = '/login'}>Portal Login →</button>
            </div>
          </div>
        </div>

        {/* Scroll indicator */}
        <div style={{ position: 'absolute', bottom: 32, left: '50%', transform: 'translateX(-50%)', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6, animation: 'lp-float 2s ease-in-out infinite' }}>
          <div style={{ width: 1, height: 40, background: 'linear-gradient(to bottom,transparent,rgba(255,255,255,0.4))' }} />
          <span style={{ fontSize: 10, color: 'rgba(255,255,255,0.3)', fontWeight: 600, letterSpacing: '0.15em', textTransform: 'uppercase' }}>Scroll</span>
        </div>
      </section>

      {/* ── Stats ── */}
      <section ref={statsRef} style={{ background: 'linear-gradient(135deg,#1960a3,#002045)', padding: '60px 24px' }}>
        <div style={{ maxWidth: 1000, margin: '0 auto', display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 24 }}>
          <StatCounter value={100} suffix="%" label="Annual Result" inView={statsInView} />
          <StatCounter value={300} suffix="+" label="Students Enrolled" inView={statsInView} />
          <StatCounter value={1000} suffix="+" label="Alumni" inView={statsInView} />
          <StatCounter value={15} suffix="+" label="Years of Excellence" inView={statsInView} />
        </div>
      </section>

      {/* ── About ── */}
      <section id="about" className="lp-section" style={{ background: '#fff' }}>
        <div className="lp-container">
          <div className="lp-grid-2">
            <div>
              <div className="lp-section-label">About Us</div>
              <h2 className="lp-section-title">A Legacy of Learning &amp; Excellence</h2>
              <p className="lp-section-desc" style={{ marginBottom: 20 }}>
                Founded in 2009, Lord Krishna Public School has been a beacon of quality education in Ishapur, Laxminagar, Mathura. We believe every child carries a unique potential that deserves to be nurtured with care, discipline, and modern pedagogy.
              </p>
              <p className="lp-section-desc" style={{ marginBottom: 32 }}>
                Our school offers a holistic environment where academics, sports, arts, and moral values go hand in hand — preparing students not just for exams, but for life.
              </p>
              <div style={{ display: 'flex', gap: 32 }}>
                {[{ label: 'Classes', value: 'Nursery – VIII' }, { label: 'Medium', value: 'English' }].map(s => (
                  <div key={s.label}>
                    <div style={{ fontSize: 18, fontWeight: 900, color: '#1960a3', fontFamily: 'Manrope,sans-serif' }}>{s.value}</div>
                    <div style={{ fontSize: 11, color: '#94a3b8', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.08em', marginTop: 2 }}>{s.label}</div>
                  </div>
                ))}
              </div>
            </div>
            {/* Principal card */}
            <div style={{ background: 'linear-gradient(145deg,#f8fafc,#eff6ff)', borderRadius: 24, padding: '40px', border: '1px solid #e2e8f0' }}>
              <div style={{ width: 72, height: 72, borderRadius: 20, background: 'linear-gradient(135deg,#1960a3,#60a5fa)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 32, marginBottom: 20 }}>👨‍🏫</div>
              <div style={{ fontSize: 11, fontWeight: 800, color: '#1960a3', textTransform: 'uppercase', letterSpacing: '0.15em', marginBottom: 8 }}>Principal's Message</div>
              <p style={{ fontSize: 15, color: '#475569', lineHeight: 1.8, marginBottom: 20, fontStyle: 'italic' }}>
                "We believe that education is not merely the transfer of knowledge, but the kindling of a flame — one that lights up a child's curiosity, character, and confidence for life."
              </p>
              <div style={{ fontSize: 14, fontWeight: 700, color: '#1e293b' }}>School Principal</div>
              <div style={{ fontSize: 12, color: '#94a3b8' }}>Lord Krishna Public School, Mathura</div>
            </div>
          </div>
        </div>
      </section>

      {/* ── Values ── */}
      <section style={{ background: '#f8fafc', padding: '80px 0' }}>
        <div className="lp-container">
          <div style={{ textAlign: 'center', marginBottom: 56 }}>
            <div className="lp-section-label">Our Philosophy</div>
            <h2 className="lp-section-title">Value-Based Education</h2>
          </div>
          <div className="lp-grid-4">
            {VALUES.map(v => (
              <div key={v.title} className="lp-card" style={{ background: '#fff', borderRadius: 20, padding: '32px 24px', boxShadow: '0 2px 16px rgba(0,32,69,0.06)', border: '1px solid #f1f5f9', textAlign: 'center' }}>
                <div style={{ fontSize: 40, marginBottom: 16 }}>{v.icon}</div>
                <h3 style={{ fontSize: 16, fontWeight: 800, color: '#1e293b', marginBottom: 10, fontFamily: 'Manrope,sans-serif' }}>{v.title}</h3>
                <p style={{ fontSize: 13, color: '#64748b', lineHeight: 1.65 }}>{v.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── Academics ── */}
      <section id="academics" className="lp-section" style={{ background: '#fff' }}>
        <div className="lp-container">
          <div className="lp-grid-2">
            <div>
              <div className="lp-section-label">Academics</div>
              <h2 className="lp-section-title">Curriculum &amp; Classes</h2>
              <p className="lp-section-desc" style={{ marginBottom: 28 }}>
                We offer a comprehensive curriculum from Nursery to Class XII, designed to build strong foundations while encouraging creativity and independent thinking.
              </p>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                {[
                  { level: 'Pre-Primary', classes: 'Nursery, LKG, UKG', color: '#10b981' },
                  { level: 'Primary', classes: 'Class I – V', color: '#3b82f6' },
                  { level: 'Middle School', classes: 'Class VI – VIII', color: '#8b5cf6' },
                ].map(r => (
                  <div key={r.level} style={{ display: 'flex', alignItems: 'center', gap: 14, padding: '14px 18px', borderRadius: 14, background: '#f8fafc', border: '1px solid #f1f5f9' }}>
                    <div style={{ width: 10, height: 10, borderRadius: '50%', background: r.color, flexShrink: 0 }} />
                    <div style={{ flex: 1 }}>
                      <span style={{ fontSize: 14, fontWeight: 700, color: '#1e293b' }}>{r.level}</span>
                      <span style={{ fontSize: 12, color: '#94a3b8', marginLeft: 10 }}>{r.classes}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
              {[
                { icon: '🏆', title: 'Board Results', desc: '100% pass rate with distinction in board examinations year after year.' },
                { icon: '🎯', title: 'Focused Learning', desc: 'Small class sizes ensure personalized attention for every student.' },
                { icon: '📊', title: 'Regular Assessment', desc: 'Continuous evaluation through tests, projects and practical exams.' },
              ].map(c => (
                <div key={c.title} className="lp-card" style={{ display: 'flex', gap: 16, padding: '20px', borderRadius: 16, background: '#f8fafc', border: '1px solid #f1f5f9' }}>
                  <div style={{ fontSize: 28, flexShrink: 0 }}>{c.icon}</div>
                  <div>
                    <h4 style={{ fontSize: 15, fontWeight: 800, color: '#1e293b', marginBottom: 6, fontFamily: 'Manrope,sans-serif' }}>{c.title}</h4>
                    <p style={{ fontSize: 13, color: '#64748b', lineHeight: 1.6 }}>{c.desc}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* ── Facilities ── */}
      <section id="facilities" style={{ background: 'linear-gradient(145deg,#001530,#002045)', padding: '80px 0' }}>
        <div className="lp-container">
          <div style={{ textAlign: 'center', marginBottom: 56 }}>
            <div style={{ fontSize: 11, fontWeight: 800, color: '#60a5fa', letterSpacing: '0.2em', textTransform: 'uppercase', marginBottom: 12 }}>Infrastructure</div>
            <h2 style={{ fontSize: 38, fontWeight: 900, color: '#fff', fontFamily: 'Manrope,sans-serif', lineHeight: 1.15 }}>World-Class Facilities</h2>
          </div>
          <div className="lp-grid-3">
            {FACILITIES.map(f => (
              <div key={f.title} className="lp-card" style={{ background: 'rgba(255,255,255,0.06)', borderRadius: 20, padding: '28px', border: '1px solid rgba(255,255,255,0.1)', backdropFilter: 'blur(8px)' }}>
                <div style={{ fontSize: 36, marginBottom: 16 }}>{f.icon}</div>
                <h3 style={{ fontSize: 16, fontWeight: 800, color: '#fff', marginBottom: 8, fontFamily: 'Manrope,sans-serif' }}>{f.title}</h3>
                <p style={{ fontSize: 13, color: 'rgba(255,255,255,0.55)', lineHeight: 1.65 }}>{f.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── Notice Board ── */}
      <section id="gallery" className="lp-section" style={{ background: '#fff' }}>
        <div className="lp-container">
          <div style={{ display: 'flex', alignItems: 'flex-end', justifyContent: 'space-between', marginBottom: 40, flexWrap: 'wrap', gap: 16 }}>
            <div>
              <div className="lp-section-label">Latest Updates</div>
              <h2 className="lp-section-title" style={{ marginBottom: 0 }}>Notice Board</h2>
            </div>
            <button className="lp-btn-primary" onClick={() => window.location.href = '/login'} style={{ padding: '10px 24px', fontSize: 13 }}>View All →</button>
          </div>
          <div style={{ background: '#f8fafc', borderRadius: 20, overflow: 'hidden', border: '1px solid #f1f5f9' }}>
            {NOTICES.map((n, i) => (
              <div key={i} className="notice-row" style={{ display: 'flex', alignItems: 'center', gap: 20, padding: '18px 24px', borderBottom: i < NOTICES.length - 1 ? '1px solid #f1f5f9' : 'none', background: '#fff', transition: 'background 150ms', cursor: 'default' }}>
                <div style={{ width: 60, textAlign: 'center', flexShrink: 0 }}>
                  <div style={{ fontSize: 18, fontWeight: 900, color: '#1960a3', fontFamily: 'Manrope,sans-serif', lineHeight: 1 }}>{n.date.split(' ')[1].replace(',', '')}</div>
                  <div style={{ fontSize: 9, fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.08em' }}>{n.date.split(' ')[0]}</div>
                </div>
                <div style={{ width: 1, height: 36, background: '#e2e8f0', flexShrink: 0 }} />
                <div style={{ flex: 1 }}>
                  <span style={{ fontSize: 14, fontWeight: 600, color: '#1e293b' }}>{n.title}</span>
                </div>
                <span style={{ padding: '4px 12px', borderRadius: 20, background: (tagColor[n.tag] || '#64748b') + '18', color: tagColor[n.tag] || '#64748b', fontSize: 11, fontWeight: 700, flexShrink: 0 }}>{n.tag}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── Contact ── */}
      <section id="contact" style={{ background: '#f8fafc', padding: '80px 0' }}>
        <div className="lp-container">
          <div style={{ textAlign: 'center', marginBottom: 56 }}>
            <div className="lp-section-label">Get In Touch</div>
            <h2 className="lp-section-title">Contact Us</h2>
          </div>
          <div className="lp-grid-3">
            {[
              { icon: '📍', title: 'Address', lines: ['Ishapur, Laxminagar', 'Mathura, Uttar Pradesh'] },
              { icon: '📞', title: 'Phone', lines: ['+91 XXXXX XXXXX', 'Mon–Sat, 8am–4pm'] },
              { icon: '✉️', title: 'Email', lines: ['info@lkpsmathura.in', 'admissions@lkpsmathura.in'] },
            ].map(c => (
              <div key={c.title} style={{ background: '#fff', borderRadius: 20, padding: '32px', boxShadow: '0 2px 16px rgba(0,32,69,0.06)', border: '1px solid #f1f5f9', textAlign: 'center' }}>
                <div style={{ fontSize: 36, marginBottom: 16 }}>{c.icon}</div>
                <h3 style={{ fontSize: 15, fontWeight: 800, color: '#1e293b', marginBottom: 10, fontFamily: 'Manrope,sans-serif' }}>{c.title}</h3>
                {c.lines.map((l, i) => <p key={i} style={{ fontSize: 13, color: '#64748b', lineHeight: 1.7 }}>{l}</p>)}
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── Footer / Login CTA ── */}
      <footer style={{ background: 'linear-gradient(145deg,#001530,#002045)', padding: '60px 24px 32px' }}>
        <div style={{ maxWidth: 1200, margin: '0 auto' }}>
          {/* CTA */}
          <div style={{ textAlign: 'center', padding: '48px 24px', background: 'rgba(255,255,255,0.05)', borderRadius: 24, border: '1px solid rgba(255,255,255,0.1)', marginBottom: 48 }}>
            <div style={{ fontSize: 11, fontWeight: 800, color: '#60a5fa', letterSpacing: '0.2em', textTransform: 'uppercase', marginBottom: 12 }}>School Management Portal</div>
            <h2 style={{ fontSize: 32, fontWeight: 900, color: '#fff', fontFamily: 'Manrope,sans-serif', marginBottom: 12 }}>Access the School Portal</h2>
            <p style={{ fontSize: 14, color: 'rgba(255,255,255,0.5)', marginBottom: 32, maxWidth: 480, margin: '0 auto 32px' }}>
              Admins, Teachers, and Parents can log in to manage academics, attendance, fees, and more.
            </p>
            <div style={{ display: 'flex', gap: 16, justifyContent: 'center', flexWrap: 'wrap' }}>
              {[
                { label: '🔐 Admin Login', desc: 'Full management access' },
                { label: '👨‍🏫 Teacher Login', desc: 'Attendance & marks' },
                { label: '👨‍👩‍👧 Parent Login', desc: 'Track your child' },
              ].map(r => (
                <button key={r.label} onClick={() => window.location.href = '/login'}
                  style={{ padding: '14px 28px', borderRadius: 14, border: '1.5px solid rgba(255,255,255,0.2)', background: 'rgba(255,255,255,0.07)', color: '#fff', cursor: 'pointer', transition: 'all 200ms', fontFamily: 'inherit', textAlign: 'left' }}
                  onMouseEnter={e => { e.currentTarget.style.background = 'rgba(96,165,250,0.15)'; e.currentTarget.style.borderColor = 'rgba(96,165,250,0.5)'; }}
                  onMouseLeave={e => { e.currentTarget.style.background = 'rgba(255,255,255,0.07)'; e.currentTarget.style.borderColor = 'rgba(255,255,255,0.2)'; }}>
                  <div style={{ fontSize: 14, fontWeight: 700 }}>{r.label}</div>
                  <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.45)', marginTop: 2 }}>{r.desc}</div>
                </button>
              ))}
            </div>
            <div style={{ marginTop: 28 }}>
              <a href="/login" style={{ display: 'inline-flex', alignItems: 'center', gap: 8, padding: '14px 36px', borderRadius: 14, background: 'linear-gradient(135deg,#1960a3,#60a5fa)', color: '#fff', fontWeight: 800, fontSize: 15, textDecoration: 'none', boxShadow: '0 8px 24px rgba(25,96,163,0.4)', transition: 'all 200ms', fontFamily: 'Manrope,sans-serif' }}>
                🔑 Go to Login Page
              </a>
            </div>
          </div>

          {/* Footer bottom */}
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 16, paddingTop: 24, borderTop: '1px solid rgba(255,255,255,0.08)' }}>
            <div>
              <div style={{ fontSize: 14, fontWeight: 800, color: '#fff', fontFamily: 'Manrope,sans-serif' }}>LORD KRISHNA PUBLIC SCHOOL</div>
              <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.35)', marginTop: 2 }}>Ishapur, Laxminagar, Mathura · Est. 2009</div>
            </div>
            <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.3)' }}>© 2026 Lord Krishna Public School. All rights reserved.</div>
          </div>
        </div>
      </footer>

      {/* ── Admission Popup ── */}
      {popup && (
        <div onClick={() => setPopup(false)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.7)', zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16, backdropFilter: 'blur(4px)' }}>
          <div onClick={e => e.stopPropagation()} style={{ position: 'relative', maxWidth: 480, width: '100%', borderRadius: 20, overflow: 'hidden', boxShadow: '0 32px 80px rgba(0,0,0,0.6)', animation: 'pop-in 400ms cubic-bezier(0.34,1.56,0.64,1) both' }}>
            <style>{`@keyframes pop-in{from{opacity:0;transform:scale(0.88) translateY(20px)}to{opacity:1;transform:none}}`}</style>
            {/* Close button */}
            <button onClick={() => setPopup(false)}
              style={{ position: 'absolute', top: 12, right: 12, width: 36, height: 36, borderRadius: '50%', background: 'rgba(0,0,0,0.55)', border: '2px solid rgba(255,255,255,0.4)', color: '#fff', fontSize: 18, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 10, lineHeight: 1, fontWeight: 700 }}>✕</button>
            {/* The actual brochure image */}
            <img src={process.env.PUBLIC_URL + '/brochure.png'} alt="Admission Open - Lord Krishna Public School"
              style={{ width: '100%', display: 'block' }} />
          </div>
        </div>
      )}
    </div>
  );
}
